INSERT INTO `products` VALUES ('09f34fa4-e1bc-4de6-b647-45c1ca313721','2026-04-03 15:20:20.504001','d0ecb343-7459-4bdc-bdff-a7edc93622db','ACTIVE','2026-04-03 15:20:37.336108','d0ecb343-7459-4bdc-bdff-a7edc93622db','Nike','Nike G.T. Jump Academy EP | JapanSport HF1804-800\r\nGiày G.T. Jump Academy lò xo giúp bạn giảm xóc khi tiếp đất, tránh bị văng khỏi ván. Với hai lớp mút mềm xếp chồng lên nhau và gót giày cong, bạn có thể tự tin nhảy và tiếp đất trên mọi sân. Với đế ngoài bằng cao su siêu bền, phiên bản này mang đến cho bạn lực bám tốt trên sân ngoài trời.Sản phẩm này được thiết kế có trách nhiệm, sử dụng vật liệu tái chế từ rác thải sau tiêu dùng và/hoặc sau sản xuất. Một trong những bước tiến lớn nhất của chúng tôi trên hành trình hướng đến mục tiêu không carbon và không rác thải là lựa chọn vật liệu, bởi vì chúng chiếm hơn 70% lượng khí thải của bất kỳ sản phẩm nào. Bằng cách tái sử dụng nhựa, sợi và vải hiện có, chúng tôi đã giảm đáng kể lượng khí thải. Mục tiêu của chúng tôi là sử dụng càng nhiều vật liệu tái chế càng tốt mà không ảnh hưởng đến hiệu suất, độ bền và kiểu dáng.','MALE','https://res.cloudinary.com/dljrbdc51/image/upload/v1775229635/shoe_shop/products/09f34fa4-e1bc-4de6-b647-45c1ca313721/49906c83-c17d-4320-998d-7697b0e87256_vang1.webp','Giày Bóng Rổ Nike Chính Hãng - Nike G.T. Jump Academy EP - Màu Cam','486e14b4-b6ad-4e96-8ebf-130b13a81cfa'),('0d8d6412-2afc-4fd5-b048-207b42636669','2026-04-03 14:48:27.970063','d0ecb343-7459-4bdc-bdff-a7edc93622db','ACTIVE','2026-04-03 14:48:27.970063','d0ecb343-7459-4bdc-bdff-a7edc93622db','Nike','Air Jordan 1 Low \r\n\r\nLuôn hợp thời, luôn tươi mới. Giày Air Jordan 1 Low mang đến cho bạn một phần lịch sử và di sản của Jordan, đồng thời mang lại sự thoải mái suốt cả ngày. Hãy chọn màu sắc yêu thích của bạn, rồi tự tin sải bước với kiểu dáng biểu tượng được chế tạo từ sự kết hợp cao cấp giữa các chất liệu và công nghệ Air tích hợp ở gót giày.','FEMALE','https://res.cloudinary.com/dljrbdc51/image/upload/v1775227705/shoe_shop/products/null/4f1d073a-97de-4472-b83e-fbab57c0343b_cam1.webp','Giày Nike Chính Hãng - Air Jordan 1 Low','2aeb5bc1-4444-4f58-8c1c-4fc876d86303'),('123aff3b-d0a8-4db0-b410-bd21b6fc6f27','2026-04-03 17:56:57.489049','d0ecb343-7459-4bdc-bdff-a7edc93622db','ACTIVE','2026-04-03 17:56:57.489049','d0ecb343-7459-4bdc-bdff-a7edc93622db','Adidas','Mang đôi giày này để có được phong cách gọn gàng, sắc sảo cùng cảm giác thoải mái. Nhờ mang hơi hướng adidas cổ điển, đôi giày trainer phong cách chạy bộ này dễ dàng cho bạn vẻ ngoài tự tin và dễ chịu. Bất kể khi tụ tập bạn bè hay nỗ lực hoàn thành to-do list cuối tuần, hãy luôn tận hưởng cảm giác thoải mái.\r\n\r\nSản phẩm này may bằng vải công nghệ Primegreen, thuộc dòng chất liệu tái chế hiệu năng cao.','MALE','https://res.cloudinary.com/dljrbdc51/image/upload/v1775239021/shoe_shop/products/123aff3b-d0a8-4db0-b410-bd21b6fc6f27/7c84a51c-21bc-44ca-8c76-2b8d2dad7219_Screenshot%202026-04-04%20005630.png','Giày Cloudfoam Pure 2.0','486e14b4-b6ad-4e96-8ebf-130b13a81cfa'),('189f2c2e-0aba-43e0-b0cc-2d8c68168f39','2026-04-03 15:26:53.864802','d0ecb343-7459-4bdc-bdff-a7edc93622db','ACTIVE','2026-04-03 15:27:43.644929','d0ecb343-7459-4bdc-bdff-a7edc93622db','Puma','CÂU CHUYỆN VỀ SẢN PHẨM\r\n\r\nTái định nghĩa giày bóng rổ với PUMA Rebound Lay-Up. Đôi giày đa năng này được trang bị phần thân bằng lưới thoáng khí vượt trội và lớp lót SoftFoam+ mang lại sự vừa vặn và hỗ trợ tối ưu. Kết hợp với công nghệ Formstrip danh tiếng của PUMA, bạn sẽ sở hữu một phong cách cổ điển kết hợp với những cải tiến hiện đại.\r\n\r\nCHI TIẾT\r\n\r\nMặt trên bằng da lộn.\r\n\r\nĐế ngoài làm từ cao su\r\n\r\nLogo PUMA đứng đầu trên lưỡi giày\r\n\r\nDải Formstrip của PUMA ở bên hông\r\n\r\nDấu hiệu PUMA ở gót chân','MALE','https://res.cloudinary.com/dljrbdc51/image/upload/v1775230061/shoe_shop/products/189f2c2e-0aba-43e0-b0cc-2d8c68168f39/33b05eed-7772-40e8-a672-21c97bfa9e4f_pumaB1.webp','Giày Thời Trang PUMA Unisex Rebound LayUp Lo SD Black-White Màu Đen','2aeb5bc1-4444-4f58-8c1c-4fc876d86303'),('2448c379-9f4e-4b2c-ad89-607a24296f5d','2026-04-03 15:42:02.648645','d0ecb343-7459-4bdc-bdff-a7edc93622db','ACTIVE','2026-04-03 15:42:02.648645','d0ecb343-7459-4bdc-bdff-a7edc93622db','Puma','CÂU CHUYỆN SẢN PHẨM\r\n\r\nNâng tầm trò chơi giày thể thao của bạn với giày thể thao nữ PUMA Skye. Được thiết kế với đế cao đầy phong cách, những đôi giày này không chỉ hợp xu hướng mà còn mang đến khả năng hỗ trợ và đệm tuyệt vời để mang lại sự thoải mái cả ngày. Giày thể thao PUma Skye là sự lựa chọn hoàn hảo để thêm nét phong cách đường phố cho bất kỳ trang phục nào, đồng thời đế dày đảm bảo độ bền và sự ổn định trong mỗi bước đi. Cho dù bạn đang tập gym hay chạy việc vặt, những đôi giày thể thao này chắc chắn sẽ giúp bạn trông đẹp và cảm thấy tuyệt vời. Nâng cấp bộ sưu tập giày dép của bạn với PUMA Skye và bước ra ngoài thật phong cách.','MALE','https://res.cloudinary.com/dljrbdc51/image/upload/v1775230920/shoe_shop/products/null/01a0a115-aef4-4e0c-aba0-0fd1ec4247dc_pumaC1.webp','Giày thời trang PUMA Nữ Skye White-Island Pink-Blue Wash Màu Trắng','2aeb5bc1-4444-4f58-8c1c-4fc876d86303'),('2d52267f-ff81-47d3-9841-f27856c3d375','2026-04-03 15:43:49.371234','d0ecb343-7459-4bdc-bdff-a7edc93622db','ACTIVE','2026-04-03 15:44:05.261468','d0ecb343-7459-4bdc-bdff-a7edc93622db','Puma','CÂU CHUYỆN SẢN PHẨM\r\n\r\nNâng tầm trò chơi giày thể thao của bạn với giày thể thao nữ PUMA Skye. Được thiết kế với đế cao đầy phong cách, những đôi giày này không chỉ hợp xu hướng mà còn mang đến khả năng hỗ trợ và đệm tuyệt vời để mang lại sự thoải mái cả ngày. Giày thể thao PUma Skye là sự lựa chọn hoàn hảo để thêm nét phong cách đường phố cho bất kỳ trang phục nào, đồng thời đế dày đảm bảo độ bền và sự ổn định trong mỗi bước đi. Cho dù bạn đang tập gym hay chạy việc vặt, những đôi giày thể thao này chắc chắn sẽ giúp bạn trông đẹp và cảm thấy tuyệt vời. Nâng cấp bộ sưu tập giày dép của bạn với PUMA Skye và bước ra ngoài thật phong cách.','FEMALE','https://res.cloudinary.com/dljrbdc51/image/upload/v1775231042/shoe_shop/products/2d52267f-ff81-47d3-9841-f27856c3d375/5cde5f86-7e7b-42ce-bdf1-b1520ddfefa9_pumaC1.webp','Giày thời trang PUMA Nữ Skye White-Island Pink-Blue Wash Màu Trắng','2aeb5bc1-4444-4f58-8c1c-4fc876d86303'),('2d8ec46f-aca5-4017-b10f-a2376f780f3d','2026-04-04 03:05:05.640428','d0ecb343-7459-4bdc-bdff-a7edc93622db','ACTIVE','2026-04-04 03:25:49.171909','d0ecb343-7459-4bdc-bdff-a7edc93622db','Adidas','Tự tin tung cú dứt điểm quyết định cùng đôi giày bóng đá sân cỏ nhân tạo Predator Club. Được thiết kế để khai phóng tiềm năng vô hạn, siêu phẩm này là sự kết hợp hoàn hảo giữa công nghệ adidas đỉnh cao và phong cách đầy uy lực. Công nghệ PowerSpine tại trung bàn chân mang lại sự ổn định tuyệt đối, giúp bạn kiến tạo nên những cú sút mạnh mẽ hơn bao giờ hết. Phần thân giày bằng chất liệu tổng hợp mềm mại đem lại sự êm ái, trong khi các vân nổi tăng cường độ bám giúp bạn điều khiển bóng với độ chính xác cực cao. Thiết kế lưỡi gà rời có dây buộc giúp việc xỏ giày trở nên dễ dàng và linh hoạt tùy chỉnh, mang lại sự vừa vặn cá nhân hóa để bạn chiếm trọn ưu thế trên sân. Hãy phá bỏ mọi giới hạn cùng NanoStrike – công nghệ lưới và dứt điểm đột phá của adidas giúp bạn di chuyển và xoay sở đầy tinh tế. Dù bạn đang mài giũa kỹ năng hay khao khát chiến thắng, đôi giày này được tạo ra để giải phóng nội lực và giúp bạn thực sự nâng tầm đẳng cấp cuộc chơi.','MALE','https://res.cloudinary.com/dljrbdc51/image/upload/v1775273150/shoe_shop/products/2d8ec46f-aca5-4017-b10f-a2376f780f3d/cba9af45-4717-4d6b-bc73-bca13032dc64_Screenshot%202026-04-04%20100411.png','Giày Bóng Đá Sân Cỏ Nhân Tạo Predator Club','25e367ee-a053-4b15-847e-b8e5a52030e2'),('3688edcc-9fb4-4557-a070-b8105946c4ef','2026-04-03 14:30:11.990025','d0ecb343-7459-4bdc-bdff-a7edc93622db','ACTIVE','2026-04-03 14:30:42.875069','d0ecb343-7459-4bdc-bdff-a7edc93622db','Nike','Air Jordan 1 Low \r\n\r\nLuôn hợp thời, luôn tươi mới. Giày Air Jordan 1 Low mang đến cho bạn một phần lịch sử và di sản của Jordan, đồng thời mang lại sự thoải mái suốt cả ngày. Hãy chọn màu sắc yêu thích của bạn, rồi tự tin sải bước với kiểu dáng biểu tượng được chế tạo từ sự kết hợp cao cấp giữa các chất liệu và công nghệ Air tích hợp ở gót giày.','MALE','https://res.cloudinary.com/dljrbdc51/image/upload/v1775226640/shoe_shop/products/3688edcc-9fb4-4557-a070-b8105946c4ef/d136f67c-b8b0-4aa0-976e-e79b4c5e0a9b_cam1.webp','Giày Nike Chính Hãng - Air Jordan 1 Low - Màu Hồng Cam','2aeb5bc1-4444-4f58-8c1c-4fc876d86303'),('438f5735-dab1-4fbd-bbb2-8b85a43f879e','2026-04-03 16:51:17.582231','d0ecb343-7459-4bdc-bdff-a7edc93622db','ACTIVE','2026-04-03 16:51:17.582231','d0ecb343-7459-4bdc-bdff-a7edc93622db','Adidas','Ra đời trên sân bóng, giày Samba là biểu tượng kinh điển của phong cách đường phố. Phiên bản này trung thành với di sản, thể hiện qua thân giày bằng da mềm, dáng thấp, nhã nhặn, các chi tiết phủ ngoài bằng da lộn và đế gum, biến đôi giày trở thành item không thể thiếu trong tủ đồ của tất cả mọi người - cả trong và ngoài sân cỏ.','MALE','https://res.cloudinary.com/dljrbdc51/image/upload/v1775235078/shoe_shop/products/null/a415d877-0c75-452a-a780-9d66a39bcea8_Screenshot%202026-04-03%20235032.png','Giày Samba OG','77bbece3-7a82-48e4-8bd7-e28ccddb67b3'),('4a955adc-05b2-4482-a65c-6d5bb391edde','2026-04-03 15:04:22.607362','d0ecb343-7459-4bdc-bdff-a7edc93622db','ACTIVE','2026-04-03 15:04:22.607362','d0ecb343-7459-4bdc-bdff-a7edc93622db','Nike','Giày Nike Chính Hãng - Air Force 1 \'07 RealTree  | JapanSport IH1221-001\r\nThoải mái, bền bỉ và vượt thời gian—đây là mẫu giày số một vì lý do chính đáng. Air Force 1 này kết hợp kiểu dáng cổ điển với họa tiết camo Realtree® để tạo nên độ bền và phong cách.\r\n\r\nƯu điểm\r\n\r\nThân giày bằng vải dệt nhẹ và bền.\r\nĐế Nike Air mang lại lớp đệm nhẹ.\r\nĐế ngoài bằng cao su với các vòng xoay cổ điển mang lại độ bám và độ bền.','MALE','https://res.cloudinary.com/dljrbdc51/image/upload/v1775228660/shoe_shop/products/null/e31109b2-41ca-42b2-9df5-f890585a53e0_BY1.jpg','Giày Nike Chính Hãng - Air Force 1 \'07 RealTree - Màu Đen/Vàng','2aeb5bc1-4444-4f58-8c1c-4fc876d86303'),('527b7945-f250-4557-bfdc-7381c8bfa5b0','2026-04-03 17:50:57.420549','d0ecb343-7459-4bdc-bdff-a7edc93622db','ACTIVE','2026-04-03 17:50:57.420549','d0ecb343-7459-4bdc-bdff-a7edc93622db','Adidas','Đôi giày adidas VL Court Bold này là định nghĩa của sự cân bằng. Giày có thiết kế cổ thấp, nhưng đặt trên đế platform nâng tầm toàn bộ outfit — cả về nghĩa đen lẫn phong cách. Thân giày bằng da, lớp lót bằng vải dệt và đế ngoài bằng cao su bền bỉ kết hợp mang đến cảm giác thoải mái bất tận cho các chuyển động hàng ngày của bạn.','MALE','https://res.cloudinary.com/dljrbdc51/image/upload/v1775238936/shoe_shop/products/527b7945-f250-4557-bfdc-7381c8bfa5b0/65e432e6-e828-40cd-bc99-f027b09c9b3e_Screenshot%202026-04-04%20004916.png','Giày VL Court Bold','486e14b4-b6ad-4e96-8ebf-130b13a81cfa'),('541c862a-1336-4f15-b059-e31ad7fe2ec1','2026-04-03 15:26:54.407689','d0ecb343-7459-4bdc-bdff-a7edc93622db','ACTIVE','2026-04-03 15:29:23.526097','d0ecb343-7459-4bdc-bdff-a7edc93622db','Puma','CÂU CHUYỆN VỀ SẢN PHẨM\r\n\r\nTái định nghĩa giày bóng rổ với PUMA Rebound Lay-Up. Đôi giày đa năng này được trang bị phần thân bằng lưới thoáng khí vượt trội và lớp lót SoftFoam+ mang lại sự vừa vặn và hỗ trợ tối ưu. Kết hợp với công nghệ Formstrip danh tiếng của PUMA, bạn sẽ sở hữu một phong cách cổ điển kết hợp với những cải tiến hiện đại.\r\n\r\nCHI TIẾT\r\n\r\nMặt trên bằng da lộn.\r\n\r\nĐế ngoài làm từ cao su\r\n\r\nLogo PUMA đứng đầu trên lưỡi giày\r\n\r\nDải Formstrip của PUMA ở bên hông\r\n\r\nDấu hiệu PUMA ở gót chân','FEMALE','https://res.cloudinary.com/dljrbdc51/image/upload/v1775230161/shoe_shop/products/541c862a-1336-4f15-b059-e31ad7fe2ec1/91ea839a-6dad-48dc-8287-e03d301ad2bb_pumaB1.webp','Giày Thời Trang PUMA Unisex Rebound LayUp Lo SD Black-White Màu Đen','2aeb5bc1-4444-4f58-8c1c-4fc876d86303'),('5fe6fca1-035a-44c5-86d8-6ea72b52e993','2026-04-